class Solution:
    def minStickers(self, stickers, target):
        from collections import Counter
        from functools import lru_cache
        counts = [Counter(s) for s in stickers]
        @lru_cache(maxsize=None)
        def dp(rem):
            if not rem:
                return 0
            need = Counter(rem)
            best = float('inf')
            first = rem[0]
            for c in counts:
                if c[first] == 0:
                    continue
                leftover = []
                for ch, k in need.items():
                    take = max(0, k - c[ch])
                    leftover.append(ch * take)
                nxt = ''.join(sorted(''.join(leftover)))
                r = dp(nxt)
                if r != float('inf'):
                    best = min(best, 1 + r)
            return best
        ans = dp(''.join(sorted(target)))
        return -1 if ans == float('inf') else ans

