class Solution:
    def minStickers(self, stickers, target):
        from functools import lru_cache
        from collections import Counter
        avail = [[0] * 26 for _ in stickers]
        for i, s in enumerate(stickers):
            for ch in s:
                avail[i][ord(ch) - 97] += 1
        @lru_cache(maxsize=None)
        def dp(rem):
            if not rem:
                return 0
            cnt = Counter(rem)
            res = float('inf')
            first = rem[0]
            fi = ord(first) - 97
            for a in avail:
                if a[fi] == 0:
                    continue
                parts = []
                for ch, k in cnt.items():
                    rema = k - a[ord(ch) - 97]
                    if rema > 0:
                        parts.append(ch * rema)
                sub = dp(''.join(sorted(''.join(parts))))
                if sub + 1 < res:
                    res = sub + 1
            return res
        ans = dp(''.join(sorted(target)))
        return -1 if ans == float('inf') else ans

