var minStickers = function(stickers, target) {
    const avail = stickers.map(s => {
        const a = new Array(26).fill(0);
        for (const ch of s) a[ch.charCodeAt(0) - 97]++;
        return a;
    });
    const memo = new Map();
    const dp = (rem) => {
        if (rem.length === 0) return 0;
        if (memo.has(rem)) return memo.get(rem);
        const cnt = {};
        for (const ch of rem) cnt[ch] = (cnt[ch] || 0) + 1;
        const first = rem[0];
        const fi = first.charCodeAt(0) - 97;
        let res = Infinity;
        for (const a of avail) {
            if (a[fi] === 0) continue;
            let parts = [];
            for (const ch in cnt) {
                const rema = cnt[ch] - a[ch.charCodeAt(0) - 97];
                if (rema > 0) parts.push(ch.repeat(rema));
            }
            const next = parts.join('').split('').sort().join('');
            const sub = dp(next);
            if (sub + 1 < res) res = sub + 1;
        }
        memo.set(rem, res);
        return res;
    };
    const ans = dp(target.split('').sort().join(''));
    return ans === Infinity ? -1 : ans;
};
